    /**
     * Helper: Forges a secured user token (JWT) for Agent Studio authenticated requests.
     *
     * @param string $secretKey   the secret key to sign the token with
     * @param string $secretKeyId the key ID to include in the JWT header (kid)
     * @param string $userId      the user identifier to include as the subject (sub) claim
     * @param int    $expiresIn   The token expiration in seconds from now. Defaults to 86400 (24 hours).
     *
     * @return string the signed JWT token
     */
    public function forgeSecuredUserToken($secretKey, $secretKeyId, $userId, $expiresIn = 86400)
    {
        $header = rtrim(strtr(base64_encode(json_encode(['alg' => 'HS256', 'typ' => 'JWT', 'kid' => $secretKeyId], JSON_UNESCAPED_SLASHES)), '+/', '-_'), '=');
        $payload = rtrim(strtr(base64_encode(json_encode(['sub' => $userId, 'exp' => time() + $expiresIn], JSON_UNESCAPED_SLASHES)), '+/', '-_'), '=');
        $signature = rtrim(strtr(base64_encode(hash_hmac('sha256', $header.'.'.$payload, $secretKey, true)), '+/', '-_'), '=');

        return $header.'.'.$payload.'.'.$signature;
    }

    private function sendRequestWithHttpInfo($method, $resourcePath, $headers, $queryParameters, $httpBody, $requestOptions, $useReadTransporter = false)
    {
        if (!isset($requestOptions['headers'])) {
            $requestOptions['headers'] = [];
        }
        if (!isset($requestOptions['queryParameters'])) {
            $requestOptions['queryParameters'] = [];
        }

        $requestOptions['headers'] = array_merge($headers, $requestOptions['headers']);
        $requestOptions['queryParameters'] = array_merge($queryParameters, $requestOptions['queryParameters']);
        $query = Query::build($requestOptions['queryParameters']);

        return $this->api->sendRequest(
            $method,
            $resourcePath.($query ? "?{$query}" : ''),
            $httpBody,
            $requestOptions,
            $useReadTransporter,
            true
        );
    }
